def main(args):
    import json
    import math

    def mean(values):
        return sum(values) / len(values) if len(values) > 0 else 0

    def std(values, ddof=1):
        if len(values) <= ddof: return 0
        m = mean(values)
        variance = sum((x - m) ** 2 for x in values) / (len(values) - ddof)
        return math.sqrt(variance)

    def rolling_mean(arr, window):
        return [
            mean(arr[i - window : i]) if i >= window else float("nan")
            for i in range(len(arr))
        ]

    def rolling_std(arr, window, ddof=1):
        return [
            std(arr[i - window : i], ddof=ddof) if i >= window else float("nan")
            for i in range(len(arr))
        ]

    def calculate_indicators(closes, highs, lows):
        n = len(closes)
        sma20 = rolling_mean(closes, 20)
        std20 = rolling_std(closes, 20)

        tr = []
        for i in range(n):
            hl = highs[i] - lows[i]
            if i == 0: tr.append(hl)
            else:
                hc = abs(highs[i] - closes[i - 1])
                lc = abs(lows[i] - closes[i - 1])
                tr.append(max(hl, hc, lc))

        atr = rolling_mean(tr, 14)
        adx = [(atr[i] / closes[i]) * 100 if not math.isnan(atr[i]) and closes[i] != 0 else float("nan") for i in range(n)]

        def get_hurst(ts):
            lags = range(2, 20)
            tau = []
            for lag in lags:
                diffs = [ts[j] - ts[j - lag] for j in range(lag, len(ts))]
                if not diffs: 
                    tau.append(0)
                    continue
                m = mean(diffs)
                variance = sum((x - m) ** 2 for x in diffs) / len(diffs)
                tau.append(math.sqrt(math.sqrt(variance)))

            log_lags = [math.log(lag) for lag in lags]
            log_tau = [math.log(t) if t > 0 else 0 for t in tau]
            n_pts = len(log_lags)
            sum_x = sum(log_lags)
            sum_y = sum(log_tau)
            sum_xx = sum(x**2 for x in log_lags)
            sum_xy = sum(log_lags[i] * log_tau[i] for i in range(n_pts))

            denom = (n_pts * sum_xx - sum_x**2)
            slope = (n_pts * sum_xy - sum_x * sum_y) / denom if denom != 0 else 0
            return slope * 2.0

        hurst_val = get_hurst(closes)
        regime = "Trending" if hurst_val > 0.55 else "Mean-Reverting"
        last_close = closes[-1]

        return {
            "ticker": "", 
            "price": round(last_close, 4),
            "regime": regime,
            "hurst_exponent": round(hurst_val, 2),
            "adx_strength": round(adx[-1], 2) if not math.isnan(adx[-1]) else 0
        }

    # Input handling
    raw_input = args.params.get('input', '{}')
    raw = {}

    if isinstance(raw_input, str):
        cleaned = raw_input.replace("```json", "").replace("```", "").strip()
        if cleaned.startswith('{') or cleaned.startswith('['):
            try: 
                raw = json.loads(cleaned)
            except: 
                try:
                    import ast
                    raw = ast.literal_eval(cleaned)
                except:
                    raw = {}
        else:
            raw = {}
    else:
        raw = raw_input

    # Diagnostic Log: What did we actually receive?
    print(f"DEBUG: Data keys received: {list(raw.keys()) if isinstance(raw, dict) else 'Not a dict'}")

    if isinstance(raw, dict):
        if "data" in raw: raw = raw["data"]
        bars_map = raw.get("bars", raw)
    else:
        bars_map = {}

    results = []

    if isinstance(bars_map, dict):
        for ticker, bar_list in bars_map.items():
            if not isinstance(bar_list, list): 
                print(f"DEBUG: Ticker {ticker} has no bar list.")
                continue

            print(f"DEBUG: Ticker {ticker} has {len(bar_list)} bars.")

            if len(bar_list) < 20:
                print(f"DEBUG: Skipping {ticker} - insufficient data (< 20 bars).")
                continue

            bar_list = sorted(bar_list, key=lambda b: b["t"])
            closes = [float(b["c"]) for b in bar_list]
            highs = [float(b["h"]) for b in bar_list]
            lows = [float(b["l"]) for b in bar_list]

            result = calculate_indicators(closes, highs, lows)
            result["ticker"] = ticker
            results.append(result)

    return {'result': json.dumps(results)}
